import { join } from 'path';
import { createOpenAPI } from 'fumadocs-openapi/server';

// Use local filtered spec (generated by scripts/fetch-openapi.ts)
// Run `bun run scripts/fetch-openapi.ts` to update the spec
// Use absolute path to ensure resolution in Vercel serverless functions
export const openapi = createOpenAPI({
  input: [join(process.cwd(), 'public/openapi.json')],
  proxyUrl: '/api/proxy',
});
